const items = $input.first().json.items || [];
const results = items.map(item => ({
  title:   item.title || '',
  snippet: item.snippet || '',
  url:     item.link || '',
  source:  item.displayLink || '',
}));
return [{ json: {
  results,
  count: results.length,
  tool: 'kb_search_web',
  query: $('Route by Tool').first().json.input.query,
}}];

const rows = $input.all().map(i => i.json);
const chunks = rows.map(r => ({
  doc_id:   r.doc_id,
  section:  r.section || '',
  text:     r.chunk_text || '',
  score:    parseFloat(r.score) || 0,
  source_uri: '',
}));
return [{ json: {
  chunks,
  count: chunks.length,
  tool: 'kb_search_local',
  query: $('Route by Tool').first().json.input.query,
}}];
